    ) : BatchItem() {
        companion object
    }

    /**
     * The request failed. The message mirrors the `Display` form of the
     * underlying [`BlazenError`].
     */
    data class Failure(
        val `errorMessage`: kotlin.String,
    ) : BatchItem() {
        companion object
    }

    companion object
}

